var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"전원, 무기를 내려 놓고 물러서라.","JPN":"全員、武器をおろして下がれ。","ENG":"Everyone lower your weapons and step back.","TWN":"所有人聽著，放下武器立刻投降。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"거부할 시에는 적대 행위로 판단하고 조치하겠다.","JPN":"拒否する場合は敵対行為とみなし、攻撃する。","ENG":"Refusing to cooperate will be considered hostile.","TWN":"若有違抗，將立刻判定為敵人進行處置。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"큭……! 이 자식들이! 갑자기 쳐들어와서 뭐 하자는 거야!","JPN":"くっ……！　こいつら！　いきなり攻め込んできて、何するつもりだ！","ENG":"Kgh...! You bastards! What do you think you're doing barging in here all of a sudden?!","TWN":"唔……！你們這些傢伙！突然衝進來是想做什麼！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"가만히 있어, 바보야.","JPN":"じっとしてて、バカ。","ENG":"Calm down, you nitwit.","TWN":"你這傻瓜，少說兩句。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"상대는 관리국이야. 함부로 덤비다간 본전도 못 건져.","JPN":"相手は管理局よ。むやみに飛びかかったら元も子もなくなる。","ENG":"It's the Administration we are up against. We can't just attack them without considering the consequences.","TWN":"對方可是管理局的人，輕舉妄動的話倒楣的可是你。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 르네, 이게 네가 벌인 짓이라고?","JPN":"それで、ルネ。これってあなたの仕業なの？","ENG":"Renée, this is all your doing?","TWN":"芮妮，你說這全是你的意思嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 그럼 나 외에 누가 하라고?","JPN":"そうだ。私以外に誰がいる？","ENG":"Yes. Who else could it be?","TWN":"沒錯，除了我之外還會有誰？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"난 그라운드 원의 도시관리국을 이끄는 몸이야.","JPN":"私はグラウンド・ワンの都市管理局を統率する立場だ。","ENG":"I'm the one who leads City Managements in Ground One.","TWN":"G1城市管理局可是歸我管的。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내 앞마당에서 벌어진 소동은 당연히 내가 처리해야지.","JPN":"管轄内で起きた騒動は当然私が処理すべきだろう。","ENG":"If there's trouble in my city, I should deal with it, of course.","TWN":"在我管區內發生的事，當然是要我自己來收拾。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 직접 나서고 싶지는 않았지만.","JPN":"こうして直接表に出たくはなかったのだが。","ENG":"Although I don't want to get directly involved like this.","TWN":"雖然我當初並沒有想親自出面的意思。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"처음 보는 아가씨인데, 부사장과 아는 사이인가?","JPN":"初めてお会いするお嬢さんだが、副社長とは知り合いなのかね？","ENG":"I haven't seen you before. Are you a friend of the Vice President?","TWN":"第一次見到這位小姐呢，是副總的朋友嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥. 태업했다고 아주 자기 입으로 광고를 하는군. 자기 아래 직급에 누가 있는지도 모르고.","JPN":"フン。自分の口でどれだけ仕事をサボっているか宣伝しているようなものだな。下に誰がいるかも知らないとは。","ENG":"Hmph. Are you showing off how you neglected your duty? How can you not recognize someone who's right below your position?","TWN":"哼，你是怕人家不知道你怠職嗎？連自己的下屬有誰都不清楚。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하긴 그러시겠지.","JPN":"まあ、そうだろう。","ENG":"But I guessed you wouldn't.","TWN":"但也不意外。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내가 시니어로 임명 받던 날에도 당신은 코빼기도 안 비췄으니까.","JPN":"私がシニアとして任命された日にもあなたは顔すら見せなかった。","ENG":"Because you never showed up on the day I was appointed as a Senior.","TWN":"我被任命為Senior的那天，你連個人影也沒見到。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"르네 말루프입니다. 사장님.","JPN":"ルネ・マルーフです。社長。","ENG":"She is Renée Maalouf, Boss.","TWN":"她是芮妮·瑪盧夫，老闆。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님이 경영에 관여하시기 직전에 그라운드 원의 시니어로 취임했죠.","JPN":"社長が経営に関わる直前にグラウンド・ワンのシニアとして就任しました。","ENG":"She was appointed as Ground One's Senior just days before you became involved in management.","TWN":"在老闆插手經營前，她被任命為G1的Senior。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};